						&lt;p class="Rubrik1Dokumentinformation" style="margin-top:0pt; margin-bottom:0pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:16pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccUtskott; -aw-sdt-title:'utskottsnamn Dokumentegenskap'"&gt;Justitieutskottet&lt;/span&gt;&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccS; -aw-sdt-title:s"&gt;s&lt;/span&gt;&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccMellanslag; -aw-sdt-title:Mellanslag"&gt; &lt;/span&gt;&lt;a name="Utlatande"&gt;&lt;/a&gt;&lt;span style="font-family:'Verdana'; font-size:16pt"&gt;betänkande&lt;/span&gt;
						&lt;/p&gt;
						&lt;p class="Dokumentbeteckning" style="margin-top:0pt; margin-bottom:0pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:16pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccRiksmote; -aw-sdt-title:'riksmote Dokumentegenskap'"&gt;2021/22&lt;/span&gt;&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccKolon; -aw-sdt-title:Kolon"&gt;:&lt;/span&gt;&lt;a name="Utskottebeteckning"&gt;&lt;/a&gt;&lt;span style="font-family:'Verdana'; font-size:16pt"&gt;JuU18&lt;/span&gt;
						&lt;/p&gt;
						&lt;p class="Rubrik1Dokumentinformation" style="margin-top:0pt; margin-bottom:0pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:16pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:16pt"&gt;&amp;#xa0;&lt;/span&gt;
						&lt;/p&gt;
					&lt;/td&gt;
				&lt;/tr&gt;
			&lt;/table&gt;
			&lt;p class="DokumentRubrik" style="-aw-sdt-tag:ccDokumentrubrik; -aw-sdt-title:'dokumentrubrik Dokumentegenskap'"&gt;
				&lt;span&gt;Tillträdesförbud till badanläggningar och bibliotek&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Sammanfattning"&gt;
				&lt;span class="tSidrubrikJA"&gt;Sammanfattning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utsko&lt;/span&gt;&lt;span&gt;ttet &lt;/span&gt;&lt;span&gt;ställer sig bakom regeringens förslag &lt;/span&gt;&lt;span&gt;att inför&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt; en möjlighet att besluta om tillträdesförbud till badanläggningar och bibliotek.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Lagändringarna föreslås träda i kraft den&lt;/span&gt;&lt;span&gt; 1 juli 2022.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt; Utskottet föreslår också två tillkännagivanden till regeringen med anledning av motionsyrkanden.&lt;/span&gt;&lt;span&gt; Enligt utskottet bör&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;de strängare regler&lt;/span&gt;&lt;span&gt; om tillträdesförbud&lt;/span&gt;&lt;span&gt; som föreslås för bibliotek också gälla för badanläggningar och butiker&lt;/span&gt;&lt;span&gt;. Vidare bör &lt;/span&gt;&lt;span&gt;tillträdesförbud kunna meddelas i fler situationer än i dag&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;När det gäller dessa tillkännagivanden finns&lt;/span&gt;&lt;span&gt; två reservationer (S,&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;C,&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;V,&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;MP). &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet föreslår att riksdagen avslår övriga motionsyrkanden. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I betänkandet finns totalt fyra reservationer (&lt;/span&gt;&lt;span&gt;S, C, V, MP&lt;/span&gt;&lt;span&gt;).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Behandlade förslag&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Proposition 2021/22:108 Tillträdesförbud till badanläggningar och bibliotek&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Fyra yrkanden&lt;/span&gt;&lt;span&gt; i följdmotioner.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Sex&lt;/span&gt;&lt;span&gt; yr&lt;/span&gt;&lt;span&gt;kanden i motioner från allmänna motionstiden 2021/22.&lt;/span&gt;
			&lt;/p&gt;
