				&lt;span&gt;Stockholm den 7 april 2022&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="PVgnar" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1948288589/1649336366734'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;På justitieutskottets vägnar&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Ordfranden" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1948288589/1649336366734'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Fredrik Lundh Sammeli&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Deltagare" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1948288589/1649336366734'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Följande ledamöter har deltagit i beslutet: Fredrik Lundh Sammeli (S), Johan Forssell (M), Petter Löberg (S), Louise Meijer (M), Maria Strömkvist (S), Johan Hedin (C), Ellen Juntti (M), Katja Nyberg (SD), Gustaf Lantz (S), Carina Ödebrink (S), Johan Pehrson (L), Tobias Andersson (SD), Martin Marmgren (MP), Ingemar Kihlström (KD), Pontus Andersson (SD), Magnus Oscarsson (KD) och Gudrun Nordborg (V).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1948288589/1649336366734'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1948288589/1649336366734'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1948288589/1649336366734'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span style="font-size:9.5pt"&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Avsnittsrubrik"&gt;
				&lt;a name="SlutUtskottsForslag"&gt;&lt;/a&gt;&lt;a name="_Toc100237101"&gt;&lt;span style="-aw-bookmark-end:SlutUtskottsForslag"&gt;&lt;/span&gt;&lt;span class="tSidrubrikJA"&gt;Redogörelse för ärendet&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I betänkandet behandlar utskottet regeringens proposition &lt;/span&gt;&lt;span&gt;2021/22:108 Tillträdesförbud till badanläggningar och bibliotek.&lt;/span&gt;&lt;span&gt; I propositionen föreslår regeringen att &lt;/span&gt;&lt;span&gt;det införs en möjlighet att besluta om tillträdesförbud til&lt;/span&gt;&lt;span&gt;l &lt;/span&gt;&lt;span&gt;badanläggningar och bibliotek&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringens förslag till riksdagsbeslut finns i bilaga 1. Regeringens lagförslag finns i bilaga 2.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Två motioner har väckts med anledning av propositionen.&lt;/span&gt;&lt;span&gt; I ärendet behandlas &lt;/span&gt;&lt;span&gt;även &lt;/span&gt;&lt;span&gt;sex&lt;/span&gt;&lt;span&gt; yrkanden&lt;/span&gt;&lt;span&gt; i motioner från allmänna&lt;/span&gt;&lt;span&gt; motionstiden 2021/22. &lt;/span&gt;&lt;span&gt;Förslagen i motionerna finns i bilaga 1.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet har &lt;/span&gt;&lt;span&gt;tidigare &lt;/span&gt;&lt;span&gt;behandlat förslag om&lt;/span&gt;&lt;span&gt; tillträdesförbud&lt;/span&gt;&lt;span&gt; till simhallar och &lt;/span&gt;&lt;span&gt;bibliotek. Våren 2017 gjorde r&lt;/span&gt;&lt;span&gt;iksdagen &lt;/span&gt;&lt;span&gt;ett tillkännagivande &lt;/span&gt;&lt;span&gt;om tillträdesförbud till simhallar och andra anläggningar (bet. &lt;/span&gt;&lt;span&gt;2016/17:JuU16, &lt;/span&gt;&lt;span&gt;rskr. 2016/17:211). &lt;/span&gt;&lt;span&gt;Vidare tillkännagav riksdagen &lt;/span&gt;&lt;span&gt;i&lt;/span&gt;&lt;span&gt; början&lt;/span&gt;&lt;span&gt; av&lt;/span&gt;&lt;span&gt; 2021&lt;/span&gt;&lt;span&gt; för regeringen&lt;/span&gt;&lt;span&gt; att &lt;/span&gt;&lt;span&gt;den &lt;/span&gt;&lt;span&gt;under 2021 sk&lt;/span&gt;&lt;span&gt;ulle&lt;/span&gt;&lt;span&gt; återkomma till riksdagen med ett förslag om tillträdesförbud till simhallar och bibliotek (bet. 2020/21:JuU13, rskr. 2020/21:169).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Justitieutskottet beslutade den 3 mars 2022 att ge kulturutskottet tillfälle att yttra sig över propositionen och motionerna i de delar de berör &lt;/span&gt;&lt;span&gt;kulturutskottet&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;beredningsområde. K&lt;/span&gt;&lt;span&gt;ultur&lt;/span&gt;&lt;span&gt;utskottets yttrande finns i bilaga 3. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Avsnittsrubrik"&gt;
				&lt;a name="_Toc100237102"&gt;&lt;span class="tSidrubrikJA"&gt;Utskottets överväganden&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:a9a71adc-f1e2-430b-9f94-ae7f8ebede9d/förslagsrutor/784618283/1647869041301; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc100237103"&gt;&lt;span&gt;Tillträdesförbud till badanläggningar och bibliotek&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc100237103"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen antar regeringens förslag om att &lt;/span&gt;&lt;span&gt;inför&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt; en möjlighet att besluta om tillträdesförbud&lt;/span&gt;&lt;span&gt; till badanläggningar och bibliotek. &lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="background-color:#ffffff"&gt;Riksdagen ställer sig bakom det som utskottet anför &lt;/span&gt;&lt;span style="background-color:#ffffff"&gt;om strängare regler för badanläggningar och butiker&lt;/span&gt;&lt;span style="background-color:#ffffff"&gt; &lt;/span&gt;&lt;span style="background-color:#ffffff"&gt;samt &lt;/span&gt;&lt;span style="background-color:#ffffff"&gt;att&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;tillträdesförbud ska kunna meddelas i fler situationer än i dag och tillkännager det&lt;/span&gt;&lt;span&gt;ta&lt;/span&gt;&lt;span&gt; för regeringen&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen&lt;/span&gt;&lt;span&gt; avslår motionsyrkanden om avslag på &lt;/span&gt;&lt;span&gt;propositionen&lt;/span&gt;&lt;span&gt; och &lt;/span&gt;&lt;span&gt;om &lt;/span&gt;&lt;span&gt;socionomer på bibliotek.&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt; -aw-sdt-tag:'a9a71adc-f1e2-430b-9f94-ae7f8ebede9d/förslagsrutor reservations text/-766663517/1648727148983'; -aw-sdt-title:'förslagsrutor reservations text'"&gt;
					&lt;span&gt;Jämför reservation 1 (V), 2 (S, C, V, MP), 3 (S, C, V, MP) och 4 (V).&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="R3" style="margin-bottom:0pt"&gt;
				&lt;span&gt;Bakgrund&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="margin-top:6pt"&gt;
				&lt;span&gt;Rörelsefriheten och möjligheten att begränsa den &lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Enligt 2 kap. 8 § regeringsformen (RF) är var och en bl.a. tillförsäkrad frihet att förflytta sig inom riket och att lämna det (rörelsefriheten). Denna rätt får dock enligt 2 kap. 20 och 21 §§ RF begränsas genom lag, men begränsningar får endast göras för att tillgodose ändamål som är godtagbara i ett demokratiskt samhälle. Begränsningen får aldrig gå utöver vad som är nödvändigt med hänsyn till det ändamål som har föranlett den (proportionalitetsprincipen) och inte heller sträcka sig så långt att den utgör ett hot mot den fria åsiktsbildningen såsom en av folkstyrelsens grundvalar. Begränsningen får inte göras enbart på grund av politisk, religiös, kulturell eller annan sådan åskådning. I förarbetena till regeringsformen framgår att det, beträffande en betydande del av de icke-absoluta grundlagsstadgade fri- och rättigheterna, inte går att ange möjligheterna till begränsning på ett mer precist sätt. Syftet med en lagreglering som inskränker dessa fri- och rättigheter måste emellertid redovisas noga. &lt;/span&gt;&lt;span&gt;En begränsning av rörelsefriheten enligt regeringsformen får inte stå i strid med skyddet mot diskriminering i 2 kap. RF. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Även den europeiska konventionen om skydd för de mänskliga rättigheterna och de grundläggande friheterna (Europakonventionen) innehåller bestämmelser om rörelsefrihet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Rätten att vistas på en &lt;/span&gt;&lt;span&gt;allmän &lt;/span&gt;&lt;span&gt;plats &lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I brottsbalken anses en plats som allmän om den är upplåten för eller regelbundet besöks av allmänheten (se t.ex. 16 kap. 11 och 16 §§). Om allmänheten har tillträde endast under vissa tider är platsen allmän under denna &lt;/span&gt;&lt;span&gt;tid men inte i övrigt. Badanläggningar och bibliotek anses alltså utgöra allmänna platser under den tid som de är tillgängliga för allmänheten. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Den som med äganderätt eller med annan rätt förfogar över en plats bestämmer normalt vem som får vistas där. Detta gäller även om platsen är allmän. Så länge den som förfogar över en allmän plats inte gör sig skyldig till diskriminering kan han eller hon fritt neka vissa personer tillträde till platsen, t.ex. därför att de vid tidigare tillfällen har gjort sig skyldiga till brott. Det är alltså möjligt att genom praktiska arrangemang, t.ex. genom att anordna bevakning av entrén till en badanläggning, se till att endast vissa personer får tillträde.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;När det gäller rätten att vistas i lokaler som tillhör det allmänna kan vissa gränsdragningsfrågor uppstå. Riksdagens ombudsmän (JO) har i flera beslut uttalat sig om allmänhetens rätt att vistas i myndigheters lokaler. Den samlade innebörden av JO:s uttalanden är att en myndighets lokaler inte utgör platser där allmänheten har rätt att vistas som man själv önskar (se bl.a. JO 2009/10 s.&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;436 och JO 2011/12 s. 594). &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;När det gäller biblioteken är situationen delvis en annan. Bibliotekens verksamhet regleras i bibliotekslagen (2013:801&lt;/span&gt;&lt;span&gt;) där det &lt;/span&gt;&lt;span&gt;framgår att biblioteken i det allmänna biblioteksväsendet ska verka för det demokratiska samhällets utveckling genom att bidra till kunskapsförmedling och fri åsiktsbildning samt att verksamheten ska finnas tillgänglig för alla. Biblioteken anses därtill ha en särskild betydelse som förmedlare och vägledande instans för grupper som saknar ekonomiska eller andra möjligheter att själva införskaffa eller hitta efterfrågade medier (se prop. 2012/13:147 Ny bibliotekslag s. 13). Enligt skollagen (2010:800) ska &lt;/span&gt;&lt;span&gt;skol&lt;/span&gt;&lt;span&gt;elever ha tillgång till skolbibliotek.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Bestämmelser som ger möjlighet att vid straffansvar förbjuda någon att få tillträde till och vistas på en viss plats, s.k. straffsanktionerade individuella förbud, finns i dag i lagen (1988:688) om kontaktförbud, lagen (2005:321) om tillträdesförbud vid idrottsarrangemang och, sedan den 1 mars 2021, även i lagen (2021:34) om tillträdesförbud till butik. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Om lagen om tillträdesförbud till butik&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Den 1 mars 2021 trädde lagen om tillträdesförbud till butik i kraft. Lagen innebär att en person kan förbjudas att få tillträde till och vistas i en butik. Den som bryter mot ett tillträdesförbud döms för överträdelse av tillträdesförbud till böter eller fängelse i högst sex månader. I ringa fall ska det dock inte dömas till ansvar. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;En person kan få tillträdesförbud, om det på grund av särskilda omständigheter finns risk för att han eller hon kommer att begå brott i butiken eller allvarligt trakassera någon som befinner sig där. Vid riskbedömningen ska särskilt beaktas om personen tidigare har begått brott i eller i anslutning till butiken. Brott som personen har begått före femton års ålder får inte beaktas. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Tillträdesförbud får meddelas för högst ett år men kan förlängas med som mest ett år i taget. Förbud får meddelas av allmän åklagare efter ansökan av en företrädare för butiken. Frågan om tillträdesförbud kan också tas upp genom att Polismyndigheten anmäler saken till åklagaren. Detta gäller under förutsättning att en företrädare för butiken samtycker till en sådan anmälan. Åklagarens beslut kan prövas av allmän domstol. Åklagaren får häva eller ändra ett förbud, om det på grund av ändrade förhållanden finns skäl till det.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3" style="margin-bottom:0pt"&gt;
				&lt;span&gt;Propositionen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="margin-top:6pt"&gt;
				&lt;span&gt;Brott och ordningsstörningar på simhallar och bibliotek&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I propositionen redogörs för &lt;/span&gt;&lt;span&gt;Brottsförebyggande rådets (&lt;/span&gt;&lt;span&gt;Brå&lt;/span&gt;&lt;span&gt;)&lt;/span&gt;&lt;span&gt; rapport Simhallar och bibliotek – En kartläggning av brott och ordningsstörningar (2020:10). &lt;/span&gt;&lt;span&gt;Av&lt;/span&gt;&lt;span&gt; rapporten framgår bl.a. att brott och ordningsstörningar förekommer i någon form på i stort sett alla simhallar, men att utsattheten varierar mycket mellan olika anläggningar. &lt;/span&gt;&lt;span&gt;Av intervjuerna framgår att det på de flesta &lt;/span&gt;&lt;span&gt;simhallar&lt;/span&gt;&lt;span&gt; förekommit någon form av bråk under året. Även hot och trakasserier är vanligt förekommande. Sexuella kränkningar av olika slag har förekommit på drygt hälften av simhallarna, och på nästan hälften av simhallarna har det riktats våld mot antingen personal eller besökare.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;När det gäller brottsliga händelser uppskattar de flesta av de intervjuade representanterna att gärningspersonerna i huvudsak är straffmyndiga och att det i huvudsak är män eller pojkar som ligger bakom händelserna. Närmare 80 procent av företrädarna bedömer att det helt eller delvis är samma personer som återkommande står för de brott som &lt;/span&gt;&lt;span&gt;begås&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Brås kartläggning omfattar även situationen på folkbibliotek. Samtliga bibliotek i kartläggningen uppger att de varit utsatta för brott och ordnings-störningar under det senaste året. Precis som för simhallarna är det stora skillnader mellan biblioteken. På de mest utsatta biblioteken har det under året inte bara förekommit många olika typer av incidenter, utan relativt många av dessa har också &lt;/span&gt;&lt;span&gt;inträffat&lt;/span&gt;&lt;span&gt; upprepade gånger. Någon form av bråk har förekommit på nästan alla bibliotek. Även hot och trakasserier är vanligt förekommande. Cirka en tredjedel av biblioteken uppger att det förekommit våld och sexuella trakasserier under perioden. Även stöld – &lt;/span&gt;&lt;span&gt;både från&lt;/span&gt;&lt;span&gt; verksamheten och &lt;/span&gt;&lt;span&gt;från&lt;/span&gt;&lt;span&gt; besökare – och skadegörelse är vanligt och rapporteras från ungefär tre av fyra bibliotek. På i stort sett alla bibliotek förekommer händelser relaterade till alkohol och narkotika såsom att personer uppträtt berusade. Bruk och försäljning av narkotika förekommer också men är mindre vanligt.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Regeringens överväganden om t&lt;/span&gt;&lt;span&gt;illträdesförbud till badanläggningar och bibliotek&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen konstaterar att ordnings&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt;törningar på de aktuella platserna har en negativ påverkan på &lt;/span&gt;&lt;span&gt;personalens arbetsmiljö. Därtill kommer att besökare på &lt;/span&gt;&lt;span&gt;badanläggningar och bibliotek påverkas negativt. Brott och allvarliga ordningsstörningar innebär en inskränkning av andra personers möjligheter att utnyttja verksamheterna. &lt;/span&gt;&lt;span&gt;Därtill har b&lt;/span&gt;&lt;span&gt;ibliotek en särskild demokratisk funktion och medborgares rätt att tryggt och säkert kunna besöka biblioteken &lt;/span&gt;&lt;span&gt;måste &lt;/span&gt;&lt;span&gt;värnas.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Mot denna bakgrund anser regeringen att det finns ett tydligt behov av ett förstärkt skydd mot brott och allvarliga trakasserier som sker på badanläggningar och bibliotek. Det framkommer också ett behov av att komma åt andra allvarliga ordningsstörande beteenden som i många fall påverkar bibliotekens verksamheter.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Tillträdesförbud skulle kunna utgöra ett verktyg&lt;/span&gt;&lt;span&gt; för att komma till rätta med &lt;/span&gt;&lt;span&gt;dessa problem&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen bedömer att d&lt;/span&gt;&lt;span&gt;e skyddsintressen som aktualiseras på badanläggningar och bibliotek främst &lt;/span&gt;&lt;span&gt;är &lt;/span&gt;&lt;span&gt;intresset av skydd för person vad gäller såväl personal som besökare. Liksom för butikernas del är även egendomsskyddet av betydelse. Den brottslighet som det handlar om att motverka är bl.a. brottslighet som inbegriper våld, hot, sexuella trakasserier samt skadegörelse och tillgreppsbrott. Även beteenden som inte nödvändigtvis är brottsliga, t.ex. allvarliga trakasserier mot enskilda, bör förhindras. Det kan därtill vara fråga om att motverka brott som stör ordningen och säkerheten, såsom narkotikabrott.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Enligt regeringen är de intressen som en reglering om tillträdesförbud till badanläggningar och bibliotek skulle skydda tillräckligt starka för att motivera en sådan lagstiftning.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Mot bakgrund av skyddsintressena och syftet med den föreslagna regleringen – att förstärka skyddet mot bl.a. brott på de aktuella platserna – bedömer regeringen även att inskränkningen av rörelsefriheten sker för att tillgodose ett godtagbart ändamål.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Vad gäller den proportionalitetsprincipen som ska göras vid begränsningar av rörelsefriheten &lt;/span&gt;&lt;span&gt;konstaterar&lt;/span&gt;&lt;span&gt; regeringen att &lt;/span&gt;&lt;span&gt;ett &lt;/span&gt;&lt;span&gt;tillträdesförbud skulle avse en geografiskt begränsad plats och grundas på en riskbedömning där tidigare misskötsamhet har särskild betydelse. &lt;/span&gt;&lt;span&gt;Vad gäller &lt;/span&gt;&lt;span&gt;en badanläggning &lt;/span&gt;&lt;span&gt;finns det förvisso &lt;/span&gt;&lt;span&gt;redan i dag möjlighet &lt;/span&gt;&lt;span&gt;att neka en person tillträde. &lt;/span&gt;&lt;span&gt;Det saknas dock möjligheter att avlägsna eller straffrättsligt ingripa mot den som överträder ett sådant förbud&lt;/span&gt;&lt;span&gt;. Att besöka en badanläggning kan därtill &lt;/span&gt;&lt;span&gt;inte sägas vara avgörande för den enskildes dagliga livsföring och ett tillträdesförbud utgör normalt sett inte heller ett hinder mot att besöka andra badanläggningar. Därtill innebär brottslighet och allvarliga trakasserier en begränsning av andra personers möjlighet att utnyttja sim- och badverksamheten. &lt;/span&gt;&lt;span&gt;Vidare&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;får badanläggningar anses vara en skyddsvärd miljö där integritet och trygghet måste värnas, inte minst eftersom många barn vistas där.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Vad gäller bibliotek&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;sakna&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt; i dag&lt;/span&gt;&lt;span&gt; lagstöd att portförbjuda personen från biblioteket&lt;/span&gt;&lt;span&gt;, vilket leder till en &lt;/span&gt;&lt;span&gt;sämre arbetsmiljö för personalen och en sämre service till allmänheten. Ett tillträdesförbud skulle i och för sig begränsa den enskildes möjlighet att ta del av biblioteksverksamheten. Ett tillträdesförbud innebär dock endast en tidsbegränsad utestängning från ett enskilt bibliotek, &lt;/span&gt;&lt;span&gt;som sker på grund av allvarlig misskötsamhet på just den platsen. Ett tillträdesförbud hindrar normalt sett inte personen från att besöka andra bibliotek. Då tillträdesförbudet är kopplat till platsen påverkas &lt;/span&gt;&lt;span&gt;inte &lt;/span&gt;&lt;span&gt;heller möjligheterna att ta del av ett biblioteks digitala aktiviteter och lånetjänster. En sådan inskränkning kan enligt regeringen inte sägas vara oproportionerlig eller stå i strid med bibliotekslagens reglering. Detta gäller särskilt som en möjlighet till tillträdesförbud skulle &lt;/span&gt;&lt;span&gt;göra det möjligt&lt;/span&gt;&lt;span&gt; för andra personer att på ett tryggare sätt ta del av biblioteksverksamheten, inklusive medborgarkontor och annan samhällsservice som i vissa fall finns i bibliotekslokaler.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;En reglering som gör det möjligt att förbjuda personer att få tillträde till och vistas på en badanläggning eller ett bibliotek skulle också sannolikt leda till minskade problem där. Att det, så&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;som framgår &lt;/span&gt;&lt;span&gt;av&lt;/span&gt;&lt;span&gt; Brås kartläggning, helt eller delvis är samma personer som återkommande står för brott och ordningsstörningar på de aktuella platserna förstärker den bilden.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Mot bakgrund av det anförda gör regeringen bedömningen att den begränsning som möjligheten till tillträdesförbud till badanläggningar och bibliotek skulle innebära inte går utöver vad som är nödvändigt med hänsyn till det ändamål som föranleder den, dvs. är proportionerlig.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen anser &lt;/span&gt;&lt;span&gt;sammanfattningsvis &lt;/span&gt;&lt;span&gt;att det bör införas en möjlighet att besluta om tillträdesförbud till badanläggningar och bibliotek.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Tillträdesförbud till badanläggningar och bibliotek&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen föreslår att tillträdesförbud ska kunna meddelas avseende badanläggningar och bibliotek, där verksamhet bedrivs som riktar sig till allmänheten. Regleringen om tillträdesförbud till dessa platser ska tas in i den lag som reglerar tillträdesförbud till butik. Lagen ska benämnas lagen om tillträdesförbud till butiker, badanläggningar och bibliotek.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regelverket avseende tillträdesförbud ska i huvudsak gälla på motsvarande sätt för de platser som omfattas av &lt;/span&gt;&lt;span&gt;den befintliga &lt;/span&gt;&lt;span&gt;lagen, såväl i fråga om processuella regler som förutsättningar för förbud.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;E&lt;/span&gt;&lt;span&gt;n person&lt;/span&gt;&lt;span&gt; bör således&lt;/span&gt;&lt;span&gt;, liksom i fråga om butiker, kunna få tillträdesförbud till en badanläggning eller ett bibliotek om det på grund av särskilda omständigheter finns risk för att han eller hon kommer att begå brott på platsen. Även risken för att en person ska allvarligt trakassera någon på platsen, utan att det nödvändigtvis är att anse som ett brott, bör kunna föranleda ett tillträdesförbud.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;När det gäller bibliotek har dock dessa en särskilt viktig uppgift som kunskapsförmedlare och att verka för fri åsiktsbildning. Allvarliga ordningsstörningar på bibliotek leder till att dessa lagstadgade uppgifter försvåras och kan därtill medföra att allmänheten väljer att inte besöka biblioteken vissa tider eller att inte besöka dem alls. Det är angeläget att skydda biblioteken från störningar av mer varierande slag. Det finns därför skäl att kunna ingripa också om det finns risk för andra störningar än sådana som är brottsliga. Även vid risk för att en person kommer &lt;/span&gt;&lt;span&gt;att&lt;/span&gt;&lt;span&gt; väsentligt störa bibliotekets verksamhet bör tillträdesförbud &lt;/span&gt;&lt;span&gt;kunna utfärdas. Med att &lt;/span&gt;&lt;span&gt;verksamheten störs väsentligt avses olika beteenden som inte nödvändigtvis är straffbara. Till skillnad från allvarliga trakasserier behöver störningarna inte heller rikta sig mot en person, utan det som avses är störningar av själva verksamheten. Det kan t.ex. handla om att någon uppträder berusat, högljutt eller aggressivt eller river ner böcker. Att störningen ska vara väsentlig innebär ett krav på att den måste nå upp till en viss nivå. Störningen måste dock relateras till att det är fråga om ett bibliotek och bedömningen bör göras utifrån vad som normalt sett anses störa verksamheten där.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Vidare bör den omständigheten att det finns risk för att en person skadar bibliotekets egendom, även utan att det är fråga om brott, kunna leda till tillträdesförbud. Så kan exempelvis vara fallet om den skadegörande handlingen skett genom grov vårdslöshet.&lt;/span&gt;&lt;span&gt;              &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Ett tillträdesförbud ska inte omfatta tillträde till och vistelse på en plats endast i syfte att rösta i val&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Ikraftträdande &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent" style="text-indent:0pt"&gt;
				&lt;span&gt;Lagändringarna föreslås träda i kraft den 1 juli 2022. Enligt regeringen behövs inte några särskilda övergångsbestämmelser.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Regeringens redovisning av tillkännagivanden&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I motionsbetänkandet om straffrättsliga frågor våren 2017 tillkännagav riksdagen för regeringen det som utskottet anför&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; om tillträdesförbud till simhallar och andra anläggningar (bet. 2016/17:JuU16, rskr. 2016/17:211). &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I samband med behandlingen av &lt;/span&gt;&lt;a name="_Hlk97549782"&gt;&lt;span&gt;propositionen Tillträdesförbud till butik och förstärkt straffrättsligt skydd mot tillgreppsbrottslighet &lt;/span&gt;&lt;/a&gt;&lt;span&gt;tillkännagav riksdagen för regeringen att regeringen under 2021 skulle återkomma till riksdagen med ett förslag om tillträdesförbud till simhallar och bibliotek (bet. 2020/21:JuU13, rskr. 2020/21:169).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Genom de förslag som lämnas i propositionen anser regeringen att dessa tillkännagivanden är tillgodosedda och att tillkännagivandena därmed är slutbehandlade.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I kommittémotion &lt;/span&gt;&lt;span&gt;2021/22:4408 av Linda Westerlund Snecker m.fl. (V)&lt;/span&gt;&lt;span&gt; begärs avslag på propositionen. I yrkande 2 begärs ett tillkännagivande om att&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;regeringen bör se över möjligheten att låta socionomer bemanna utsatta bibliotek&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I kommittémotion 2021/22:4416 av Johan Forssell m.fl. (M) yrkande 1 begärs ett tillkännagivande om att de strängare regler som föreslås för bibliotek också ska gälla för badanläggningar och butiker&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;En lik&lt;/span&gt;&lt;span&gt;n&lt;/span&gt;&lt;span&gt;ande begäran framställs i kommittémotion 2021/22:3786 av Johan Forssell m.fl. (M) yrkande 10.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I &lt;/span&gt;&lt;span&gt;kommittémotion 2021/22:4416 av Johan Forssell m.fl. (M) yrkande&lt;/span&gt;&lt;span&gt; 2 begärs att beslut om tillträdesförbud ska kunna meddelas i fler situationer än i dag. &lt;/span&gt;&lt;span&gt;Liknande yrkanden framställs i kommittémotionerna 2021/22:3786 av Johan Forssell m.fl. (M) yrkande 9, 2021/22:&lt;/span&gt;&lt;a name="_Hlk93408097"&gt;&lt;span&gt;2386&lt;/span&gt;&lt;/a&gt;&lt;span&gt; av Tobias Andersson m.fl. (SD) yrkande 2 och 2021/22:2527 av Adam Marttinen m.fl. (SD) yrkande 34. I den sistnämnda motionen efterfrågas även att förbudet ska kunna användas preventivt, inte bara efter en lagakraftvunnen dom.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I kommittémotion&lt;/span&gt;&lt;span&gt;erna&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;2021/22:3786 av Johan Forssell m.fl. (M)&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;yrkande 11 och &lt;/span&gt;&lt;span&gt;2021/22:3974 av Johan Pehrson m.fl. (L)&lt;/span&gt;&lt;span&gt; yrkande 27 begärs &lt;/span&gt;&lt;span&gt;att regeringen &lt;/span&gt;&lt;span&gt;ska&lt;/span&gt;&lt;span&gt; återkomma med förslag om tillträdesförbud även till bibliotek och simhallar&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Kulturutskottets yttrande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Kulturutskottet har yttrat sig över propositionen och följdmotionerna i de delar som de berör kulturutskottets beredningsområde. I yttrandet anför kulturutskottet bl.a. följande:&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Quote"&gt;
				&lt;span&gt;Utskottet välkomnar de förändringar i lagen (2021:34) om tillträdesförbud till butik som regeringen föreslår. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Citatindrag" style="margin-bottom:0pt"&gt;
				&lt;span&gt;Badanläggningar och bibliotek är platser som är öppna för allmänheten. Badanläggningar och bibliotek som drivs i offentlig regi tillhandahåller som redovisats ovan en samhällsservice. Biblioteken i det allmänna biblioteksväsendet ska verka för det demokratiska samhällets utveckling och verksamheten ska finnas tillgänglig för alla. Det ligger därför i samhällets intresse att motverka brott och andra ordningsstörningar på badanläggningar och bibliotek för att öka tryggheten och trivseln. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Citatindrag" style="margin-top:0pt; margin-bottom:0pt"&gt;
				&lt;span&gt;Tillträdesförbud ska enligt propositionen kunna meddelas i fråga om badanläggningar och bibliotek där det bedrivs verksamhet som riktar sig till allmänheten. Utskottet instämmer med regeringen i att en möjlighet att besluta om tillträdesförbud torde leda till minskade problem på utsatta platser och ökad trygghet för personal och besökare. Utskottet bedömer liksom regeringen att ett införande av en möjlighet till tillträdesförbud utgör en effektiv åtgärd för att bemöta problemen med ordningsstörningar. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Citatindrag" style="margin-top:0pt"&gt;
				&lt;span&gt;Utskottet föreslår därför att justitieutskottet tillstyrker propositionen i de behandlade delarna och avstyrker motionsyrkandena.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare riksdagsbehandling&lt;/span&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utöver vad som redogjorts för &lt;/span&gt;&lt;span&gt;ovan har&lt;/span&gt;&lt;span&gt; riksdagen &lt;/span&gt;&lt;span&gt;vid behandlingen av &lt;/span&gt;&lt;span&gt;propositionen Tillträdesförbud till butik och förstärkt straffrättsligt skydd mot tillgreppsbrottslighet behandlat &lt;/span&gt;&lt;span&gt;en &lt;/span&gt;&lt;span&gt;motion&lt;/span&gt;&lt;span&gt; om att regeringen skulle återkomma till riksdagen med ett förslag om att även risk för ordningsstörningar och skadegörelse ska kunna leda till tillträdesförbud till butik. Utskottet konstaterade då att risken för att en person avsiktligen kommer att göra sig skyldig till skadegörelse redan omfattades av regeringens lagförslag. När det gällde risken för att en person på annat sätt, t.ex. genom grov vårdslöshet, skulle orsaka skada på egendom eller väsentligen störa verksamheten instämde &lt;/span&gt;&lt;span&gt;utskottet i regeringens bedömning att det inte framkommit någon anledning att låta lagen om tillträdesförbud till butik ta sikte även på sådana situationer. Utskottet var således inte berett att ställa sig bakom det begärda tillkänna&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;givandet och avstyrkte motionsyrkandet. Riksdagen följde utskottets förslag &lt;/span&gt;&lt;span&gt;(bet. 2020/21:JuU13, rskr. 2020/21:169).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Ytterligare information&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Stockholms stadsbibliotek har beviljats särskilda medel från Stockholm&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt; stad för att anställa en socionom för ett års pilotprojekt med namnet ”Bibliotekssocionom”. Under ett år ska en nyanställd socionom arbeta med att utveckla bibliotekets arbete med socialt utsatta. Målet är att öka personalens trygghet och bygga strukturerade nätverk med andra myndigheter och organisationer. Enligt uppgift på stadsbibliotekets hemsida ska socionomen bemanna och verka uppsökande i biblioteksrummet, utbilda personalen i social utsatthet och bemötande samt skapa en struktur för samverkan med andra myndigheter och organisationer. Projektet löper fram till mars 2022.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande &lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Enligt utskottet visar bl.a. Brås rapport att det i dag finns problem med ordningsstörningar på såväl simhallar som badhus, och att störningarna även omfattar kriminella handlingar. &lt;/span&gt;&lt;span&gt;Det finns, som regeringen också anför, därför &lt;/span&gt;&lt;span&gt;ett tydligt behov av ett förstärkt skydd mot brott och allvarliga trakasserier som sker på badanläggningar och bibliotek&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Som framgår ovan har riksdagen &lt;/span&gt;&lt;span&gt;också &lt;/span&gt;&lt;span&gt;efterfrågat den typ av tillträdesförbud som nu föreslås i propositionen.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Vidare delar utskottet&lt;/span&gt;&lt;span&gt; de överväganden som regeringen gör i sin proportionalitets&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;bedömning&lt;/span&gt;&lt;span&gt; och anser även i övrigt att lagförslaget har fått en väl avvägd utformning. &lt;/span&gt;&lt;span&gt;Kulturutskottet har inte heller haft något att invända mot att propositionen bifalls.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Sammantaget välkomnar utskottet lagförslaget och anser att propositionen ska bifallas och&lt;/span&gt;&lt;span&gt; att&lt;/span&gt;&lt;span&gt; motion 2021/22:4408 (V) yrkande 1 ska avslås.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Genom lagförslaget får motionerna&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;2021/22:3786 (M)&lt;/span&gt;&lt;span&gt; yrkande 11 och &lt;/span&gt;&lt;span&gt;2021/22:3974&lt;/span&gt;&lt;span&gt; (L) yrkande 27&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;om att &lt;/span&gt;&lt;span&gt;införa tillträdesförbud i s&lt;/span&gt;&lt;span&gt;i&lt;/span&gt;&lt;span&gt;mhallar och bibliotek anses&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;tillgodosedda och&lt;/span&gt;&lt;span&gt; de&lt;/span&gt;&lt;span&gt; avstyrks därför.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Vad &lt;/span&gt;&lt;span&gt;gäller motionsyrkandet om att de strängare regler som föreslås för bibliotek också ska gälla för badanläggningar och butiker &lt;/span&gt;&lt;span&gt;konstaterar &lt;/span&gt;&lt;span&gt;utskottet &lt;/span&gt;&lt;span&gt;att&lt;/span&gt;&lt;span&gt; personer som ägnar sig åt att störa verksamheten eller orsakar betydande skador utgör ett problem även &lt;/span&gt;&lt;span&gt;i&lt;/span&gt;&lt;span&gt; badanläggningar och butiker. Utöver de negativa effekterna för besökares och kunders trygghet samt de anställdas arbetsmiljö kan störningarna leda till ekonomisk skada. Utskottet anser därför att det finns anledning för riksdagen att rikta ett tillkännagivande till regeringen om att återkomma till riksdagen med förslag om att de strängare regler&lt;/span&gt;&lt;span&gt; om tillträdesförbud&lt;/span&gt;&lt;span&gt; som föreslås för bibliotek också ska gälla för &lt;/span&gt;&lt;span&gt;badanläggningar och butiker. &lt;/span&gt;&lt;span&gt;Därmed &lt;/span&gt;&lt;span&gt;tillstyrker &lt;/span&gt;&lt;span&gt;utskottet&lt;/span&gt;&lt;span&gt; motion&lt;/span&gt;&lt;span&gt;erna 2021/22:3786 (M) yrkande 10 och&lt;/span&gt;&lt;span&gt; 2021/22:4416 (M) yrkande 1. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Vidare&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;finns det uppgifter om att lagen om tillträdesförbud inte tillämpas i den utsträckning som bl.a. handlare hade förväntat sig. Även om lagen endast varit i kraft i ett år anser utskottet därför &lt;/span&gt;&lt;span&gt;att det &lt;/span&gt;&lt;span&gt;finns anledning att generellt se över hur&lt;/span&gt;&lt;span&gt; den&lt;/span&gt;&lt;span&gt; kan tillämpas i större utsträckning än vad som hittills har varit fallet. Utskottet tillstyrker därför motion&lt;/span&gt;&lt;span&gt;erna &lt;/span&gt;&lt;span&gt;2021/22:2386 (SD) yrkande 2, 2021/22:3786 (M) yrkande 9 och &lt;/span&gt;&lt;span&gt;2021/22:4416 (M) yrkande 2 &lt;/span&gt;&lt;span&gt;samt&lt;/span&gt;&lt;span&gt; tillstyrker delvis motion 2021/22:2527 (SD) yrkande 34.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet&lt;/span&gt;&lt;span&gt;, som &lt;/span&gt;&lt;span&gt;noterar att det pågår ett pilotprojekt i Stockholms stad &lt;/span&gt;&lt;span&gt;med namnet ”Bibliotekssocionom&lt;/span&gt;&lt;span&gt;”&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;finner inte anledning att &lt;/span&gt;&lt;span&gt;ta något initiativ med anledning av motion &lt;/span&gt;&lt;span&gt;2021/22:4408 (V)&lt;/span&gt;&lt;span&gt; yrkande 2. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Avslutningsvis har utskottet inte något att invända mot regeringens redovisning i propositionen av de tillkännagivanden som redogörs för ovan.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Avsnittsrubrik"&gt;
				&lt;a name="_Toc100237104"&gt;&lt;span class="tSidrubrikJA"&gt;Reservationer&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;table cellspacing="0" cellpadding="0" style="border-collapse:collapse; margin-left:0pt; width:294.2pt"&gt;
				&lt;tr&gt;
					&lt;td style="vertical-align:top; width:22pt"&gt;
						&lt;p class="NormalNoll" style="margin-top:0pt; margin-bottom:3.1pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:12.5pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;1.&lt;/span&gt;
						&lt;/p&gt;
					&lt;/td&gt;
					&lt;td style="vertical-align:top; width:272.2pt"&gt;
						&lt;p class="Reservationsrubrik" style="margin-top:0pt; margin-bottom:3.1pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:12.5pt"&gt;
							&lt;a name="_Toc100237105"&gt;&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;Tillträdesförbud till badanläggningar och bibliotek, punkt 1 (V)&lt;/span&gt;&lt;/a&gt;
						&lt;/p&gt;
					&lt;/td&gt;
				&lt;/tr&gt;
			&lt;/table&gt;
			&lt;p class="Normalutanluftfre" style="margin-left:22pt; page-break-inside:avoid; page-break-after:avoid; -aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;av Gudrun Nordborg (V).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Förslag till riksdagsbeslut&lt;/span&gt;
			&lt;/p&gt;
			&lt;p style="margin-bottom:3.1pt; -aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Jag anser att förslaget till riksdagsbeslut under punkt 1 borde ha följande lydelse:&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Riksdagen avslår regeringens förslag.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="text-indent:11.3pt; -aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Därmed bifaller riksdagen motion &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:4408 av Linda Westerlund Snecker m.fl. (V) yrkande 1 och &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;avslår proposition 2021/22:108 punkterna 1–4 och motionerna &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:3786 av Johan Forssell m.fl. (M) yrkande 11 och &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:3974 av Johan Pehrson m.fl. (L) yrkande 27.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:82252a16-ed8f-49be-a10c-5d03a0464a73/reservationer/280138742/1649336367328; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Jag&lt;/span&gt;&lt;span&gt; har full förståelse för det obehag som personal och övriga besökare kan uppleva om en person beter sig hotfullt eller trakasserar sin omgivning. Rätten att röra sig fritt är dock grundlagsskyddad och för att begränsa en sådan rättighet krävs det mycket starka skäl. En begränsning måste även vara proportio&lt;/span&gt;&lt;span&gt;nerlig. Jag &lt;/span&gt;&lt;span&gt;bedömer att det ingrepp som ett tillträdesförbud innebär i den enskildes rätt att röra sig fritt inte står i proportion till de problem som det avser att lösa. Vidare är det oklart om tillträdesförbudet i praktiken verkligen kommer att förbättra säkerheten för besökare och arbetsmiljön för de anställda. &lt;/span&gt;&lt;span&gt;Jag&lt;/span&gt;&lt;span&gt; kan se farhågor med förslaget eftersom personal riskerar att bli ännu mer utsatt för trakasserier och/eller hot och våld om de hävdar att en viss person inte är välkommen på grund av att &lt;/span&gt;&lt;span&gt;ett &lt;/span&gt;&lt;span&gt;tillträdesförbud. Ett avvisande av en motsträvig person kräver vidare att polis eller väktare tillkallas precis som i&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;dag. Det kommer även fortsättningsvis att uppstå situationer där dessa inte är omedelbart tillgängliga för att ingripa mot den aktuella personen. Enligt &lt;/span&gt;&lt;span&gt;min &lt;/span&gt;&lt;span&gt;mening är det inte rimligt att anställda vare sig på badanläggningar eller bibliotek ska behöva konfrontera och upplysa personer om att de är belagda med tillträdesförbud. Det minst riskfyllda i en utsatt situation med en hotfull eller påverkad person är om personalen agerar på ett lågaffektivt sätt och kallar på polis eller väktare.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Sammantaget anser jag att de skäl som regeringen anför inte är tillräckligt starka för att införa ett straffsanktionerat förbud för enskilda att vistas i badanläggningar och bibliotek. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;table cellspacing="0" cellpadding="0" style="border-collapse:collapse; margin-left:0pt; width:294.2pt"&gt;
				&lt;tr&gt;
					&lt;td style="vertical-align:top; width:22pt"&gt;
						&lt;p class="NormalNoll" style="margin-top:0pt; margin-bottom:3.1pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:12.5pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;2.&lt;/span&gt;
						&lt;/p&gt;
					&lt;/td&gt;
					&lt;td style="vertical-align:top; width:272.2pt"&gt;
						&lt;p class="Reservationsrubrik" style="margin-top:0pt; margin-bottom:3.1pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:12.5pt"&gt;
							&lt;a name="_Toc100237106"&gt;&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;Risk för andra störningar som grund för tillträdesförbud, punkt 2 (S, C, V, MP)&lt;/span&gt;&lt;/a&gt;
						&lt;/p&gt;
					&lt;/td&gt;
				&lt;/tr&gt;
			&lt;/table&gt;
			&lt;p class="Normalutanluftfre" style="margin-left:22pt; page-break-inside:avoid; page-break-after:avoid; -aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;av Fredrik Lundh Sammeli (S), Petter Löberg (S), Maria Strömkvist (S), Johan Hedin (C), Gustaf Lantz (S), Carina Ödebrink (S), Martin Marmgren (MP) och Gudrun Nordborg (V).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="-aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Förslag till riksdagsbeslut&lt;/span&gt;
			&lt;/p&gt;
			&lt;p style="margin-bottom:3.1pt; -aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Vi anser att förslaget till riksdagsbeslut under punkt 2 borde ha följande lydelse:&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Riksdagen avslår motionerna &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:3786 av Johan Forssell m.fl. (M) yrkande 10 och &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:4416 av Johan Forssell m.fl. (M) yrkande 1.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:b876531a-fb00-4df9-a555-e0065eaeeae4/reservationer/-420225338/1649336367331; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;V&lt;/span&gt;&lt;span&gt;i&lt;/span&gt;&lt;span&gt; konstatera&lt;/span&gt;&lt;span&gt;r&lt;/span&gt;&lt;span&gt; att tillträdesförbud utgör ett undantag från den grundlagsskyddade fria rörligheten och att bibliotek har en lagstadgad uppgift som kunskapsförmedlare och att verka för fri åsiktsbildning. Allvarliga ordningsstörningar på bibliotek leder till att dessa uppgifter försvåras och kan därtill medföra att allmänheten väljer att inte besöka biblioteken vissa tider eller att inte besöka dem alls. Det finns därför anledning för en strängare bedömning när det gäller just bibliotek&lt;/span&gt;&lt;span&gt;. Vi anser &lt;/span&gt;&lt;span&gt;inte att det &lt;/span&gt;&lt;span&gt;har &lt;/span&gt;&lt;span&gt;framkommit tillräckliga skäl för att låta den stängare regeln gälla även&lt;/span&gt;&lt;span&gt; för&lt;/span&gt;&lt;span&gt; badanläggningar och butiker&lt;/span&gt;&lt;span&gt; och vi &lt;/span&gt;&lt;span&gt;menar&lt;/span&gt;&lt;span&gt; d&lt;/span&gt;&lt;span&gt;är&lt;/span&gt;&lt;span&gt;för&lt;/span&gt;&lt;span&gt; att riksdagen &lt;/span&gt;&lt;span&gt;inte &lt;/span&gt;&lt;span&gt;bör ta något initiativ i enlighet med motionerna. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:41894776-3967-4bd5-944e-38c150fb5051/reservationer/1577173726/1649336367335; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;table cellspacing="0" cellpadding="0" style="border-collapse:collapse; margin-left:0pt; width:294.2pt"&gt;
				&lt;tr&gt;
