			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:41894776-3967-4bd5-944e-38c150fb5051/reservationer/1577173726/1649336367335; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:2386 av Tobias Andersson m.fl. (SD) yrkande 2, &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:41894776-3967-4bd5-944e-38c150fb5051/reservationer/1577173726/1649336367335; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:2527 av Adam Marttinen m.fl. (SD) yrkande 34, &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:41894776-3967-4bd5-944e-38c150fb5051/reservationer/1577173726/1649336367335; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:3786 av Johan Forssell m.fl. (M) yrkande 9 och &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:41894776-3967-4bd5-944e-38c150fb5051/reservationer/1577173726/1649336367335; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:4416 av Johan Forssell m.fl. (M) yrkande 2.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:41894776-3967-4bd5-944e-38c150fb5051/reservationer/1577173726/1649336367335; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:41894776-3967-4bd5-944e-38c150fb5051/reservationer/1577173726/1649336367335; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Vi konstatera&lt;/span&gt;&lt;span&gt;r&lt;/span&gt;&lt;span&gt; att &lt;/span&gt;&lt;span&gt;lagen om tillträdesförbud nyligen infördes och &lt;/span&gt;&lt;span&gt;att det genom den nu behandlade propositionen införs nya platser som omfattas av bestämmelserna. Vi anser att frågan om att utöka möjligheterna att meddela tillträdesförbud är för tidigt väckt och vi utgår från att &lt;/span&gt;&lt;span&gt;regeringen kommer att följa upp lagstiftningen&lt;/span&gt;&lt;span&gt; när den &lt;/span&gt;&lt;span&gt;har &lt;/span&gt;&lt;span&gt;varit på plats en tid och det finns ett tillräckligt underlag för en sådan uppföljning&lt;/span&gt;&lt;span&gt;. Vi anser därmed att det inte&lt;/span&gt;&lt;span&gt; finns skäl för riksdagen att nu ta något initiativ med anledning av motionen. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;table cellspacing="0" cellpadding="0" style="border-collapse:collapse; margin-left:0pt; width:294.2pt"&gt;
				&lt;tr&gt;
					&lt;td style="vertical-align:top; width:22pt"&gt;
						&lt;p class="NormalNoll" style="margin-top:0pt; margin-bottom:3.1pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:12.5pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;4.&lt;/span&gt;
						&lt;/p&gt;
					&lt;/td&gt;
					&lt;td style="vertical-align:top; width:272.2pt"&gt;
						&lt;p class="Reservationsrubrik" style="margin-top:0pt; margin-bottom:3.1pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:12.5pt"&gt;
							&lt;a name="_Toc100237108"&gt;&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;Socionomer på bibliotek, punkt 4 (V)&lt;/span&gt;&lt;/a&gt;
						&lt;/p&gt;
					&lt;/td&gt;
				&lt;/tr&gt;
			&lt;/table&gt;
			&lt;p class="Normalutanluftfre" style="margin-left:22pt; page-break-inside:avoid; page-break-after:avoid; -aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;av Gudrun Nordborg (V).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="-aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Förslag till riksdagsbeslut&lt;/span&gt;
			&lt;/p&gt;
			&lt;p style="margin-bottom:3.1pt; -aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Jag anser att förslaget till riksdagsbeslut under punkt 4 borde ha följande lydelse:&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Riksdagen ställer sig bakom det som anförs i reservationen och tillkännager detta för regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="text-indent:11.3pt; -aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Därmed bifaller riksdagen motion &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;2021/22:4408 av Linda Westerlund Snecker m.fl. (V) yrkande 2.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:77a7b67a-28eb-44de-902b-e3d918883391/reservationer/1256465458/1649336367340; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Jag är kritiskt till införandet av tillträdesförbud av anledningar som bl.a. utvecklas &lt;/span&gt;&lt;span&gt;i reservation 1.&lt;/span&gt;&lt;span&gt; Jag anser därtill att det är särskilt olyckligt att denna typ av förbud införs på bibliotek, då dessa plat&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt;er har en särställning i vårt demokratiska samhälle, och alla inskränkningar av människors tillgång till bibliotek bör därför göras med stor försiktighet.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Jag menar också att en stor del av de ordningsstörningar som förekommer på bibliotek är kopplade till social utsatthet. Det handlar t.ex. om besökare som är hemlösa, personer i missbruk och personer som lider av psykisk ohälsa och som ofta har en svår livssituation.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Även om folkbiblioteken är en kommunal angelägenhet menar jag att regeringen borde ha sett över alternativa åtgärder för att komma till rätta med ordningsstörningar, exempelvis genom &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;överväga hur socionomer kan underlätta för biblioteken &lt;/span&gt;&lt;span&gt;med &lt;/span&gt;&lt;span&gt;att minska stök och ordningsstörningar. Jag anser att det är rimligt att regeringen tar ett sådant övergripande ansvar för biblioteken eftersom deras funktion i vårt demokratiska samhälle är central. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Bilaga"&gt;
				&lt;span class="tBilagaJA"&gt;Bilaga 1&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Bilagerubrik"&gt;
				&lt;a name="_Toc100237109"&gt;&lt;span class="tSidrubrikJA"&gt;Förteckning över behandlade förslag&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;p class="Rubrik2bilaga" style="-aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;a name="_Toc100237110"&gt;&lt;span&gt;Propositionen&lt;/span&gt;&lt;/a&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;h4 style="-aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;Proposition 2021/22:108 Tillträdesförbud till badanläggningar och bibliotek:&lt;/span&gt;
			&lt;/h4&gt;
			&lt;p class="Yrkandelista" style="margin-bottom:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;1.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen antar regeringens förslag till lag om ändring i lagen (2021:34) om tillträdesförbud till butik.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Yrkandelista" style="margin-top:0pt; margin-bottom:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;2.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen antar regeringens förslag till lag om ändring i lagen (1998:620) om belastningsregister.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Yrkandelista" style="margin-top:0pt; margin-bottom:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;3.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen antar regeringens förslag till lag om ändring i offentlighets- och sekretesslagen (2009:400).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Yrkandelista" style="margin-top:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;4.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen antar regeringens förslag till lag om ändring i lagen (2015:485) om erkännande och uppföljning av beslut om övervakningsåtgärder inom Europeiska unionen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Rubrik2bilaga" style="-aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;a name="_Toc100237111"&gt;&lt;span&gt;Följdmotionerna&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;h4 style="-aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;2021/22:4408 av Linda Westerlund Snecker m.fl. (V):&lt;/span&gt;
			&lt;/h4&gt;
			&lt;p class="Yrkandelista" style="margin-bottom:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;1.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen avslår proposition 2021/22:108.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Yrkandelista" style="margin-top:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;2.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen ställer sig bakom det som anförs i motionen om att regeringen bör se över möjligheten att låta socionomer bemanna utsatta bibliotek och tillkännager detta för regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h4 style="-aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;2021/22:4416 av Johan Forssell m.fl. (M):&lt;/span&gt;
			&lt;/h4&gt;
			&lt;p class="Yrkandelista" style="margin-bottom:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;1.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen ställer sig bakom det som anförs i motionen om att de strängare regler som föreslås för bibliotek också ska gälla för badanläggningar och butiker och tillkännager detta för regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Yrkandelista" style="margin-top:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-912719232/1648729860818'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;2.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen ställer sig bakom det som anförs i motionen om att beslut om tillträdesförbud ska kunna meddelas i fler situationer än i dag och tillkännager detta för regeringen.&lt;/span&gt;
